        thr_param=st.selectbox("Parametre",list(thr_ranges.keys()),
                               format_func=lambda x:x.replace("_"," "),key="thr_p_dash")
        rows=[]; prev_s=None; transitions=[]
        for val in thr_ranges[thr_param]:
            ti=inp.copy(); ti[thr_param]=float(val)
